```cpp
#include <hexi/hexi.h>
#include <vector>
#include <string>
#include <cstdint>
#include <span>

struct NetworkPacket {
    uint32_t packet_id;
    std::string username;
    std::vector<uint32_t> scores;
    std::string metadata;
};

NetworkPacket deserialize_packet(const std::span<const uint8_t> buffer) {
    // Create buffer_adaptor from the input buffer
    hexi::buffer_adaptor<std::span<const uint8_t>> adaptor(const_cast<std::span<const uint8_t>&>(buffer));

    NetworkPacket packet;

    // Read packet_id using default operator>>
    adaptor >> packet.packet_id;

    // Read username using prefixed adaptor for std::string
    adaptor >> hexi::prefixed(packet.username);

    // Read score count using prefixed adaptor for std::vector<uint32_t>
    adaptor >> hexi::prefixed(packet.scores);

    // Read metadata using null_terminated adaptor for std::string
    adaptor >> hexi::null_terminated(packet.metadata);

    // Skip any remaining padding bytes
    size_t remaining_bytes = adaptor.size() - adaptor.total_read();
    if (remaining_bytes > 0) {
        adaptor.skip(remaining_bytes);
    }

    return packet;
}

struct PacketInfo {
    uint32_t packet_id;
    std::string_view username;
};

PacketInfo extract_packet_info(const std::span<const uint8_t> buffer) {
    PacketInfo info;

    // Create buffer_adaptor from the input buffer
    hexi::buffer_adaptor<std::span<const uint8_t>> adaptor(const_cast<std::span<const uint8_t>&>(buffer));

    // Use span() adaptor to get zero-copy view of packet_id
    std::span<uint32_t> id_span(1);
    adaptor >> hexi::span(id_span);
    info.packet_id = *id_span.data();

    // Read username using prefixed adaptor to get string_view
    adaptor >> hexi::prefixed(info.username);

    // Read score count and skip the scores vector data
    uint32_t score_count;
    adaptor >> score_count;
    adaptor.skip(score_count * sizeof(uint32_t));

    return info;
}
```

## Key Implementation Points:

1. **Buffer Adaptor Creation**: Created `buffer_adaptor` from the input `std::span<const uint8_t>` buffer using `const_cast` to handle the const buffer reference.

2. **Default Operator>>**: Used the default `operator>>` for arithmetic types to read `packet_id`.

3. **Prefixed Adaptor**: Used `hexi::prefixed` adaptor for both `std::string` (username) and `std::vector<uint32_t>` (scores) as specified.

4. **Null-Terminated Adaptor**: Used `hexi::null_terminated` adaptor for reading the metadata string.

5. **Padding Skip**: Calculated remaining bytes using `adaptor.size() - adaptor.total_read()` and skipped them using `adaptor.skip()`.

6. **Span Adaptor**: Used `hexi::span` adaptor to get a zero-copy view of the packet_id in `extract_packet_info`.

7. **Score Vector Skipping**: Read the score count and skipped the actual data using `adaptor.skip(count * sizeof(uint32_t))`.

