#include <hexi/hexi.h>
#include <cstdint>
#include <span>
#include <string_view>

struct PacketHeader {
    uint8_t version;
    uint8_t flags;
    uint16_t packet_id;
};

PacketHeader read_packet_header(const std::span<const uint8_t> buffer) {
    // Create a buffer adaptor from the input span
    hexi::buffer_adaptor adaptor(const_cast<std::span<uint8_t>>(buffer));

    // Use span() to read the header with zero-copy
    // PacketHeader is 4 bytes (uint8_t + uint8_t + uint16_t)
    auto header_span = adaptor.span<PacketHeader>(1);

    // Return the header by value (zero-copy since we're just copying the struct)
    return *header_span.data();
}

std::string_view read_message_until_delimiter(const std::span<const uint8_t> buffer) {
    // Create a buffer adaptor from the input span
    hexi::buffer_adaptor adaptor(const_cast<std::span<uint8_t>>(buffer));

    // Use view() to read null-terminated string with zero-copy
    // Default delimiter is 0 (null terminator)
    return adaptor.view();
}
```

