#include <hexi/detail/intrusive_storage.h>
#include <vector>
#include <cstdint>

template<size_t block_size = 1024>
std::vector<uint8_t> preview_data_without_consuming(const hexi::detail::intrusive_storage<block_size>& storage, size_t bytes_to_preview) {
    std::vector<uint8_t> destination(bytes_to_preview);
    storage.copy(destination.data(), bytes_to_preview);
    return destination;
}

template<size_t block_size = 1024>
struct BufferStatus {
    size_t readable_size;
    size_t free_space;
};

BufferStatus<> check_buffer_status(const hexi::detail::intrusive_storage<1024>& storage) {
    BufferStatus<> status;
    status.readable_size = storage.size();
    status.free_space = 1024 - storage.size(); // Using fixed 1024 since template parameter is fixed at 1024
    return status;
}

template<size_t block_size = 1024>
void reset_buffer(hexi::detail::intrusive_storage<block_size>& storage) {
    storage.clear();
}
```

## Key Implementation Points:

1. **`preview_data_without_consuming`**:
   - Creates a destination vector with the requested size
   - Uses `storage.copy()` which doesn't advance the read pointer (as per reference material)
   - Returns the populated vector

2. **`check_buffer_status`**:
   - Uses `storage.size()` to get readable data size
   - Calculates free space as `block_size - storage.size()`
   - Returns the BufferStatus struct with both values

3. **`reset_buffer`**:
   - Directly calls `storage.clear()` which resets both read and write offsets to 0
   - As specified in the reference material, this sets `read_offset = 0` and `write_offset = 0`

