#include <hexi/pmc/buffer_read_adaptor.h>
#include <hexi/pmc/buffer_write_adaptor.h>
#include <vector>
#include <cstdint>
#include <cassert>

std::vector<uint8_t> write_and_read_data(const std::vector<uint8_t>& input_data) {
    // Create a buffer to hold the data
    std::vector<uint8_t> buffer;

    // Create buffer_write_adaptor instance
    hexi::pmc::buffer_write_adaptor<std::vector<uint8_t>> writer(buffer);

    // Check free space before writing
    assert(writer.free() >= input_data.size() && "Insufficient buffer space");

    // Write data using write() method
    writer.write(input_data.data(), input_data.size());

    // Create buffer_read_adaptor instance
    hexi::pmc::buffer_read_adaptor<std::vector<uint8_t>> reader(buffer);

    // Check readable size
    assert(reader.size() == input_data.size() && "Size mismatch after writing");

    // Read data back using read() method
    std::vector<uint8_t> output_data(reader.size());
    reader.read(output_data.data(), output_data.size());

    return output_data;
}

std::vector<uint8_t> peek_data_without_advancing(const std::vector<uint8_t>& buffer_data, std::size_t peek_size) {
    // Create buffer_read_adaptor instance
    hexi::pmc::buffer_read_adaptor<std::vector<uint8_t>> reader(buffer_data);

    // Use read_ptr() to get pointer to current read position
    const uint8_t* read_pointer = reader.read_ptr();

    // Use copy() method to peek at data without moving read cursor
    std::vector<uint8_t> peeked_data(peek_size);
    reader.copy(peeked_data.data(), peek_size);

    // Use read() to actually consume the data (advance read pointer)
    std::vector<uint8_t> consumed_data(peek_size);
