struct ProtocolPacket {
    uint32_t message_id;
    std::vector<uint16_t> data_values;
    uint32_t checksum;
};

std::vector<uint8_t> serialize_protocol_packet(const ProtocolPacket& packet) {
    // Create a buffer to hold the serialized data
    std::vector<uint8_t> buffer;

    // Create a buffer_adaptor for the vector
    hexi::buffer_adaptor<std::vector<uint8_t>> adaptor(buffer);

    // Create a binary_stream with the adaptor
    hexi::binary_stream<decltype(adaptor)> stream(adaptor);

    // Convert message_id to big-endian and write
    uint32_t big_message_id = hexi::endian::native_to_big(packet.message_id);
    stream.write(&big_message_id, 1);

    // Convert and write data_values vector
    std::vector<uint16_t> big_data_values;
    big_data_values.reserve(packet.data_values.size());
    for (auto value : packet.data_values) {
        uint16_t big_value = hexi::endian::native_to_big(value);
        big_data_values.push_back(big_value);
    }
    stream.write_container(big_data_values);

    // Convert checksum to big-endian and write
    uint32_t big_checksum = hexi::endian::native_to_big(packet.checksum);
    stream.write(&big_checksum, 1);

    return buffer;
}

ProtocolPacket deserialize_protocol_packet(const std::span<const uint8_t> buffer) {
    ProtocolPacket packet;

    // Create a buffer_adaptor for the span
    hexi::buffer_adaptor<const std::span<const uint8_t>> adaptor(buffer);

    // Create a binary_stream with the adaptor
    hexi::binary_stream<decltype(adaptor)> stream(adaptor);

    // Read and convert message_id
    uint32_t message_id;
    stream.read(&message_id, 1);
    packet.message_id = hexi::endian::big_to_native(message_id);

    // Read and convert data_values count
    uint32_t data_count;
    stream.read(&data_count, 1);
    packet.data_values.resize(hexi::endian::big_to_native(data_count));

    // Read and convert data_values
    for (auto& value : packet.data_values) {
        uint16_t raw_value;
        stream.read(&raw_value, 1);
        value = hexi::endian::big_to_native(raw_value);
    }

    // Read and convert checksum
    uint32_t checksum;
    stream.read(&checksum, 1);
    packet.checksum = hexi::endian::big_to_native(checksum);

    return packet;
}

struct ProtocolHeader {
    uint32_t message_id;
};

ProtocolHeader extract_protocol_header(const std::span<const uint8_t> buffer) {
