    hexi::buffer_adaptor<const std::span<const uint8_t>> adaptor(buffer);

    // Create a binary_stream with the adaptor
    hexi::binary_stream<decltype(adaptor)> stream(adaptor);

    // Read and convert message_id
    uint32_t message_id;
    stream.read(&message_id, 1);
    packet.message_id = hexi::endian::big_to_native(message_id);

    // Read and convert data_values count
    uint32_t data_count;
    stream.read(&data_count, 1);
    packet.data_values.resize(hexi::endian::big_to_native(data_count));

    // Read and convert data_values
    for (auto& value : packet.data_values) {
        uint16_t raw_value;
        stream.read(&raw_value, 1);
        value = hexi::endian::big_to_native(raw_value);
    }

    // Read and convert checksum
    uint32_t checksum;
    stream.read(&checksum, 1);
    packet.checksum = hexi::endian::big_to_native(checksum);

    return packet;
}

