        // Serialization: write the data
        adaptor.write(sensor_id);

        // Convert and write each temperature with runtime endianness conversion
        for (auto t : temperatures) {
            float converted = hexi::endian::conditional_reverse<std::endian::native, std::endian::little>(t);
            adaptor.write(converted);
